import Foundation

enum RequestType: String {
    case get = "GET"
    case post = "POST"
}

class NetworkManager {
    
    func sendRequest(to urlString: String, type: RequestType, completion: @escaping (Data?, URLResponse?, Error?) -> Void) {
        guard let url = URL(string: urlString) else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = type.rawValue
        
        //Allow both secure and insecure connections
        URLSession.shared.configuration.requestAllowsArbitraryLoadsInForeground = true

        let task = URLSession.shared.dataTask(with: request) { (data, response, error) in
            completion(data, response, error)
        }
        
        //Start the task
        task.resume()
    }
    
}

